import sys

class Solution:
    def maximumPoints(self, edges, coins, k):
        n = len(coins)
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        sys.setrecursionlimit(10000)

        def dfs(node, parent, halvings):
            val = coins[node]
            for _ in range(halvings):
                val //= 2
            take_all = val - k
            take_half = val // 2
            for child in adj[node]:
                if child == parent:
                    continue
                take_all += dfs(child, node, halvings)
                take_half += dfs(child, node, halvings + 1)
            return max(take_all, take_half)

        return dfs(0, -1, 0)

