var maximumPoints = function(edges, coins, k) {
    const n = coins.length;
    const CAP = 14;
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }
    const parent = new Array(n).fill(-1);
    const visited = new Array(n).fill(false);
    const order = [];
    const stack = [0];
    visited[0] = true;
    while (stack.length) {
        const node = stack.pop();
        order.push(node);
        for (const nxt of adj[node]) {
            if (!visited[nxt]) {
                visited[nxt] = true;
                parent[nxt] = node;
                stack.push(nxt);
            }
        }
    }
    const dp = Array.from({ length: n }, () => new Array(CAP + 1).fill(0));
    for (let idx = order.length - 1; idx >= 0; idx--) {
        const node = order[idx];
        for (let h = 0; h <= CAP; h++) {
            const val = coins[node] >> h;
            let optionA = val - k;
            let optionB = Math.floor(val / 2);
            for (const child of adj[node]) {
                if (child === parent[node]) continue;
                optionA += dp[child][h];
                optionB += dp[child][Math.min(h + 1, CAP)];
            }
            dp[node][h] = Math.max(optionA, optionB);
        }
    }
    return dp[0][0];
};
